(function () {
    var index = window.MOVIE_SEARCH_INDEX || [];
    var form = document.querySelector('[data-search-form]');
    var input = document.querySelector('[data-search-input]');
    var results = document.querySelector('[data-search-results]');
    var title = document.querySelector('[data-search-title]');
    var summary = document.querySelector('[data-search-summary]');
    var quickButtons = Array.prototype.slice.call(document.querySelectorAll('[data-search-word]'));

    function paramsQuery() {
        return new URLSearchParams(window.location.search).get('q') || '';
    }

    function card(movie) {
        var tags = (movie.tags || []).slice(0, 3).map(function (tag) {
            return '<span>' + escapeHtml(tag) + '</span>';
        }).join('');

        return [
            '<article class="movie-card">',
            '    <a class="poster" href="' + escapeHtml(movie.url) + '" aria-label="观看 ' + escapeHtml(movie.title) + '">',
            '        <img src="' + escapeHtml(movie.image) + '" alt="' + escapeHtml(movie.title) + '" loading="lazy">',
            '        <span class="play-badge">▶</span>',
            '    </a>',
            '    <div class="movie-card-body">',
            '        <a class="movie-title" href="' + escapeHtml(movie.url) + '">' + escapeHtml(movie.title) + '</a>',
            '        <p>' + escapeHtml(movie.summary) + '</p>',
            '        <div class="meta-row">',
            '            <span>' + movie.year + '</span>',
            '            <span>' + escapeHtml(movie.region) + '</span>',
            '            <span>★ ' + movie.rating + '</span>',
            '        </div>',
            '        <div class="tag-row">' + tags + '</div>',
            '    </div>',
            '</article>'
        ].join('\n');
    }

    function escapeHtml(value) {
        return String(value || '').replace(/[&<>"']/g, function (char) {
            return {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;',
                "'": '&#039;'
            }[char];
        });
    }

    function search(query) {
        var q = String(query || '').trim().toLowerCase();
        if (input) {
            input.value = query || '';
        }

        if (!q) {
            if (title) {
                title.textContent = '请输入关键词';
            }
            if (summary) {
                summary.textContent = '可以搜索片名、年份、地区、类型和标签。';
            }
            if (results) {
                results.innerHTML = '';
            }
            return;
        }

        var matched = index.filter(function (movie) {
            var haystack = [
                movie.title,
                movie.year,
                movie.region,
                movie.genre,
                (movie.tags || []).join(' '),
                movie.summary
            ].join(' ').toLowerCase();
            return haystack.indexOf(q) !== -1;
        }).slice(0, 120);

        if (title) {
            title.textContent = '搜索结果：' + query;
        }
        if (summary) {
            summary.textContent = '找到 ' + matched.length + ' 个相关影片，最多展示 120 条结果。';
        }
        if (results) {
            results.innerHTML = matched.map(card).join('\n');
        }
    }

    if (form) {
        form.addEventListener('submit', function (event) {
            event.preventDefault();
            var q = input ? input.value.trim() : '';
            history.replaceState(null, '', q ? ('?q=' + encodeURIComponent(q)) : location.pathname);
            search(q);
        });
    }

    quickButtons.forEach(function (button) {
        button.addEventListener('click', function () {
            var word = button.getAttribute('data-search-word') || '';
            history.replaceState(null, '', '?q=' + encodeURIComponent(word));
            search(word);
        });
    });

    search(paramsQuery());
})();
